<h5 class="mb-3"><i class="bx bx-ruler"></i> Mesures</h5><div class="row" id="editMeasureFields">@php $editFields=['epaule'=>'Épaule','manche'=>'Manche','poitrine'=>'Poitrine','taille'=>'Taille','longueur'=>'Longueur','fesse'=>'Fesse','tour_manche'=>'Tour de manche','longueur_poitrine'=>'Longueur poitrine','longueur_taille'=>'Longueur taille','longueur_fesse'=>'Longueur fesse','longueur_jupe'=>'Longueur Jupe','ceinture'=>'Ceinture','longueur_pantalon'=>'Longueur Pantalon','cuisse'=>'Cuisse','corps'=>'Cou']; @endphp @foreach($editFields as $name=>$label)<div class="col-md-6 mb-3 edit-measure-field" data-field="{{ $name }}"><label class="form-label">{{ $label }}</label><input class="form-control" inputmode="decimal" data-edit-measure="{{ $name }}"></div>@endforeach</div>
</div></div></div><div class="modal-footer"><button class="btn btn-secondary" data-bs-dismiss="modal">Annuler</button><button id="saveClientEdit" class="btn btn-primary" onclick="saveClientEdit()">Enregistrer</button></div></div></div></div>
