@push('scripts')
<script src="{{ asset('assets/plugins/sweetalert2/sweetalert2.all.min.js') }}"></script>
<script>
let editingClient=null,editingMeasure=null,isCreatingMeasure=false,editModelPhoto=null,editHabitPhoto=null;
const qs=s=>document.querySelector(s),all=s=>[...document.querySelectorAll(s)];
const storageUrl=p=>p?`{{ asset('storage') }}/${String(p).replace(/^\/+|storage\//g,'')}`:null;
const sortedMeasures=c=>[...(c?.mesures||[])].sort((a,b)=>new Date(b.date_mesure||0)-new Date(a.date_mesure||0));
const modelName=(m,i)=>m?.modele_nom?.trim()||`Modèle #${i+1}`;
const modelImage=m=>storageUrl(m?.photo_path)||(m?.sexe==='Homme'?`{{ asset('assets/images/model3.jpg') }}`:`{{ asset('assets/images/model4.jpg') }}`);
async function request(url,data=null){const response=await fetch(url,{method:data?'POST':'GET',body:data||undefined,headers:{Accept:'application/json','X-Requested-With':'XMLHttpRequest','X-CSRF-TOKEN':document.querySelector('meta[name="csrf-token"]').content}}),json=await response.json();if(!response.ok)throw new Error(json.message||Object.values(json.errors||{}).flat().join('\n'));return json}
qs('#clientTableSearch').oninput=e=>{let shown=0;all('.client-table-row').forEach(row=>{const visible=row.dataset.search.includes(e.target.value.toLowerCase());row.classList.toggle('d-none',!visible);if(visible)shown++});qs('#noFilteredClients').classList.toggle('d-none',shown>0)};
async function openClientDetail(id){try{qs('#detailClientName').textContent='Chargement...';qs('#detailContent').innerHTML='<div class="text-center py-4"><div class="spinner-border text-primary"></div></div>';qs('#detailMedia').innerHTML='';new bootstrap.Modal(qs('#clientDetailModal')).show();const{client:c}=await request(`{{ url('/clients') }}/${id}`);const ms=sortedMeasures(c);qs('#detailClientName').textContent=`${c.prenom||''} ${c.nom||''}`;qs('#detailMedia').innerHTML=ms.length?ms.map((m,i)=>`<div class="border rounded p-2 mb-2 model-preview-card"><div class="small fw-bold mb-2 text-truncate">${modelName(m,i)}</div><img src="${modelImage(m)}" class="img-fluid rounded"></div>`).join(''):`<img src="${modelImage(null)}" class="img-fluid rounded">`;const total=ms.reduce((s,m)=>s+Number(m.prix||0),0);qs('#detailContent').innerHTML=ms.length?`<div class="alert alert-secondary mb-3"><div class="d-flex justify-content-between"><strong>${ms.length} modèle(s)</strong><strong>Total: ${total.toLocaleString('fr-FR')} FCFA</strong></div></div>`+ms.map((m,i)=>measureDetail(m,i)).join(''):'<div class="alert alert-info">Aucune mesure disponible</div>'}catch(e){qs('#detailContent').innerHTML=`<div class="alert alert-danger">Erreur : ${e.message}</div>`}}
function measureDetail(m,i){const labels={epaule:'Épaule',manche:'Manche',poitrine:'Poitrine',taille:'Taille',longueur:'Longueur',fesse:'Fesse',tour_manche:'Tour de manche',longueur_poitrine:'Longueur poitrine',longueur_taille:'Longueur taille',longueur_fesse:'Longueur fesse',longueur_jupe:'Longueur Jupe',ceinture:'Ceinture',longueur_pantalon:'Longueur Pantalon',cuisse:'Cuisse',corps:'Cou'};let rows=Object.entries(labels).filter(([k])=>m[k]!==null&&m[k]!==''&&m[k]!==undefined).map(([k,l])=>`<li class="list-group-item d-flex justify-content-between"><span>${l}</span><b>${m[k]}</b></li>`).join('');return `<ul class="list-group mb-3"><li class="list-group-item fw-bold bg-light"><div class="d-flex justify-content-between"><span>${modelName(m,i)}</span><span>${m.sexe||''} ${m.type_vetement?'• '+m.type_vetement:''}</span></div></li>${m.prix?`<li class="list-group-item fw-bold bg-success text-white d-flex justify-content-between"><span>Prix du modèle:</span><span class="badge bg-light text-dark fs-6">${Number(m.prix).toLocaleString('fr-FR')} FCFA</span></li>`:''}<li class="list-group-item"><b>Description:</b><p class="text-muted small mb-0">${m.description||'Aucune description fournie'}</p></li>${rows}${m.habit_photo_path?`<li class="list-group-item"><b>Photo de l'habit:</b><div class="mt-2 text-center"><img src="${storageUrl(m.habit_photo_path)}" class="img-fluid" style="max-width:200px"></div></li>`:''}</ul>`}
async function openClientEdit(id){try{new bootstrap.Modal(qs('#clientEditModal')).show();qs('#editNom').value='';qs('#editPrenom').value='';qs('#editContact').value='';qs('#editModelsList').innerHTML='<div class="text-center py-3"><div class="spinner-border text-primary spinner-border-sm"></div> Chargement...</div>';const{client}=await request(`{{ url('/clients') }}/${id}`);editingClient=client;qs('#editNom').value=client.nom||'';qs('#editPrenom').value=client.prenom||'';qs('#editContact').value=client.contact||'';renderEditModels();selectEditMeasure(0)}catch(e){Swal.fire('Erreur',e.message||'Impossible de charger le client','error');bootstrap.Modal.getInstance(qs('#clientEditModal'))?.hide()}}
function renderEditModels(){const ms=sortedMeasures(editingClient);qs('#editModelsList').innerHTML=ms.length?ms.map((m,i)=>`<button type="button" class="list-group-item list-group-item-action edit-model-item ${!isCreatingMeasure&&editingMeasure?.id===m.id?'active':''}" onclick="selectEditMeasure(${i})"><div class="d-flex justify-content-between"><div><b>${modelName(m,i)}</b><div class="small text-muted">${m.sexe||''} ${m.type_vetement?'• '+m.type_vetement:''}</div></div><span class="badge bg-secondary rounded-pill">${m.prix||0} FCFA</span></div></button>`).join(''):'<p class="text-muted small p-2 mb-0">Aucun modèle — cliquez sur <b>Nouveau modèle</b> pour en créer un.</p>'}
function selectEditMeasure(index){const ms=sortedMeasures(editingClient);editingMeasure=ms[index]||null;isCreatingMeasure=false;qs('#newMeasureNotice').classList.add('d-none');qs('#deleteEditMeasure').classList.toggle('d-none',!editingMeasure);fillEditMeasure(editingMeasure||{sexe:editingClient.sexe||'Femme'});renderEditModels()}
function fillEditMeasure(m){const sexe=m.sexe||editingClient.sexe||'Femme';all('.edit-sex').forEach(r=>r.checked=r.value===sexe);qs('#editFemaleTypes').classList.toggle('d-none',sexe!=='Femme');qs('#editPrix').value=m.prix||'';qs('#editModeleNom').value=m.modele_nom||'';qs('#editDescription').value=m.description||'';editModelPhoto=editHabitPhoto=null;qs('#editPhotoPreview').src=modelImage(m);const habit=storageUrl(m.habit_photo_path);qs('#editHabitPreview').src=habit||'';qs('#editHabitPreview').classList.toggle('d-none',!habit);qs('#noEditHabit').classList.toggle('d-none',!!habit);all('[data-edit-measure]').forEach(input=>input.value=m[input.dataset.editMeasure]??'');setEditType((m.type_vetement||'').toUpperCase()||(sexe==='Homme'?'HOMME':''),false)}
function startNewEditMeasure(){const base=editingMeasure||{};editingMeasure=null;isCreatingMeasure=true;qs('#newMeasureNotice').classList.remove('d-none');qs('#deleteEditMeasure').classList.add('d-none');fillEditMeasure({...base,id:null,prix:'',modele_nom:'',description:'',photo_path:null,habit_photo_path:null});renderEditModels()}
const editSets={ROBE:['epaule','manche','poitrine','taille','longueur','fesse','tour_manche','longueur_poitrine','longueur_taille','longueur_fesse'],JUPE:['epaule','manche','poitrine','taille','longueur','longueur_jupe','ceinture','fesse','tour_manche','longueur_poitrine','longueur_taille','longueur_fesse'],HOMME:['epaule','manche','longueur','longueur_pantalon','ceinture','cuisse','poitrine','corps','tour_manche']};let editType='';
function setEditType(type,update=true){editType=type;all('.edit-type').forEach(c=>c.classList.toggle('border-primary',c.dataset.type===type));all('.edit-type').forEach(c=>c.classList.toggle('bg-light',c.dataset.type===type));all('.edit-measure-field').forEach(x=>x.classList.toggle('d-none',!(editSets[type]||[]).includes(x.dataset.field)));if(update&&type==='HOMME')all('.edit-sex').forEach(r=>r.checked=r.value==='Homme')}
all('.edit-type').forEach(c=>c.onclick=()=>setEditType(c.dataset.type));all('.edit-sex').forEach(r=>r.onchange=e=>{const femme=e.target.value==='Femme';qs('#editFemaleTypes').classList.toggle('d-none',!femme);setEditType(femme?(editType==='JUPE'?'JUPE':'ROBE'):'HOMME')});
qs('#editModelPhoto').onchange=e=>{editModelPhoto=e.target.files[0]||null;if(editModelPhoto)qs('#editPhotoPreview').src=URL.createObjectURL(editModelPhoto)};qs('#editHabitPhoto').onchange=e=>{editHabitPhoto=e.target.files[0]||null;if(editHabitPhoto){qs('#editHabitPreview').src=URL.createObjectURL(editHabitPhoto);qs('#editHabitPreview').classList.remove('d-none');qs('#noEditHabit').classList.add('d-none')}};
async function saveClientEdit(){const nom=qs('#editNom').value.trim(),prenom=qs('#editPrenom').value.trim(),contact=qs('#editContact').value.trim(),sexe=all('.edit-sex').find(r=>r.checked)?.value;if(!nom||!prenom||!sexe)return Swal.fire('Erreur','Nom, Prénom et Sexe sont obligatoires.','error');const button=qs('#saveClientEdit');button.disabled=true;try{const info=new FormData();info.append('_method','PUT');info.append('nom',nom);info.append('prenom',prenom);info.append('contact',contact);info.append('sexe',sexe);await request(`{{ url('/clients') }}/${editingClient.id}`,info);if(editType){const modeleNom=qs('#editModeleNom').value.trim();if(!modeleNom){button.disabled=false;return Swal.fire('Erreur','Veuillez nommer le modèle.','error')}const data=new FormData();data.append('sexe',sexe);data.append('type_vetement',editType);data.append('prix',qs('#editPrix').value);data.append('modele_nom',modeleNom);data.append('description',qs('#editDescription').value);all('[data-edit-measure]').forEach(i=>{if(!i.closest('.d-none'))data.append(i.dataset.editMeasure,i.value)});if(editModelPhoto)data.append('photo',editModelPhoto);if(editHabitPhoto)data.append('habitPhoto',editHabitPhoto);const isNew=isCreatingMeasure||!editingMeasure;if(!isNew)data.append('_method','PUT');const endpoint=isNew?`{{ url('/clients') }}/${editingClient.id}/mesures`:`{{ url('/clients') }}/${editingClient.id}/mesures/${editingMeasure.id}`;const result=await request(endpoint,data);await Swal.fire({icon:'success',title:'Succès',text:result.message,timer:1800,showConfirmButton:false})}else{await Swal.fire({icon:'success',title:'Client mis à jour',timer:1500,showConfirmButton:false})}window.location.reload()}catch(error){Swal.fire('Erreur',error.message||'Une erreur est survenue','error');button.disabled=false}}
async function deleteClient(id){const result=await Swal.fire({title:'Supprimer ce client ?',text:'Toutes ses mesures seront supprimées.',icon:'warning',showCancelButton:true,confirmButtonColor:'#d33',confirmButtonText:'Oui, supprimer !',cancelButtonText:'Annuler'});if(!result.isConfirmed)return;try{const data=new FormData();data.append('_method','DELETE');await request(`{{ url('/clients') }}/${id}`,data);await Swal.fire({icon:'success',title:'Supprimé !',timer:1500,showConfirmButton:false});window.location.reload()}catch(e){Swal.fire('Erreur',e.message||'Impossible de supprimer le client','error')}}
async function deleteCurrentMeasure(){if(!editingClient||!editingMeasure)return;const result=await Swal.fire({title:'Supprimer ce modèle ?',icon:'warning',showCancelButton:true,confirmButtonText:'Supprimer',cancelButtonText:'Annuler',confirmButtonColor:'#d33'});if(!result.isConfirmed)return;try{const data=new FormData();data.append('_method','DELETE');await request(`{{ url('/clients') }}/${editingClient.id}/mesures/${editingMeasure.id}`,data);await Swal.fire({icon:'success',title:'Modèle supprimé',timer:1500,showConfirmButton:false});window.location.reload()}catch(e){Swal.fire('Erreur',e.message||'Erreur lors de la suppression','error')}}
</script>
@endpush
